import type {
  FieldValues,
  Path,
  PathValue,
  UseFormReturn,
} from "react-hook-form";
import type {
  CreateJobPayload,
  UpdateJobPayload,
} from "../../types/jobs.types";
import {
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { RichTextEditor } from "@/components/ui/rich-text-editor";
import { Button } from "@/components/ui/button";
import { Sparkles } from "lucide-react";
import { useJobActions } from "../../hooks/useJobsActions";
import { memo, useMemo } from "react";
import { Spinner } from "@/components/ui/spinner";
import { toast } from "sonner";
import StarBorder from "@/components/StarBorder";

type JobFormValues = CreateJobPayload | UpdateJobPayload;
type JobFormBase = FieldValues & {
  description?: string;
  title?: string;
  department?: string;
  employmentType?: string;
  country?: string;
  experienceLevel?: string;
};

interface DescriptionEditorProps<T extends JobFormBase = CreateJobPayload> {
  form: UseFormReturn<T>;
}

export function DescriptionEditor<T extends JobFormBase = CreateJobPayload>({
  form,
}: DescriptionEditorProps<T>) {
  const { generateDescription, loading } = useJobActions();
  const descriptionField = "description" as Path<T>;
  const descriptionValue = form.watch(descriptionField);
  const getButtonText = useMemo(
    () => (descriptionValue ? "Enhance with AI" : "Generate with AI"),
    [descriptionValue],
  );

  const handleGenerateDescription = async () => {
    try {
      const values = form.getValues();
      if (!values.title || !values.department) {
        throw new Error(
          "Title and Department are required to generate a description.",
        );
      }

      const generatedDescription = await generateDescription({
        title: values.title ?? "",
        department: values.department ?? "",
        employmentType: values.employmentType,
        location: values.country,
        seniority: values.experienceLevel,
      });
      form.setValue(
        descriptionField,
        (generatedDescription?.context ?? "") as PathValue<T, Path<T>>,
      );
    } catch (error) {
      toast.error(
        (error as Error).message ||
          "An error occurred while generating the job description.",
      );
    }
  };

  return (
    <FormField
      control={form.control}
      name={descriptionField}
      render={({ field }) => (
        <FormItem>
          <FormLabel className="mb-0 flex justify-between items-center">
            <div>Description</div>
            <div>
              <StarBorder
                as="button"
                className="custom-class"
                color="magenta"
                speed="5s"
                onClick={handleGenerateDescription}
                disabled={loading}
              >
                {/* <Button
                  size="sm"
                  type="button"
                  className="inline-flex items-center gap-2 rounded-full bg-gradient-to-r from-indigo-500 via-sky-500 to-emerald-400 px-3 py-2 text-white shadow-sm transition hover:-translate-y-[1px] hover:shadow-md disabled:opacity-70 disabled:hover:translate-y-0"
                > */}
                  <ButtonLoadingWrapper
                    isLoading={loading}
                    loadingText="Generating..."
                  >
                    <Sparkles className="h-4 w-4 text-white" />
                    {getButtonText}
                  </ButtonLoadingWrapper>
                {/* </Button> */}
              </StarBorder>
            </div>
          </FormLabel>
          <FormControl>
            <RichTextEditor
              value={typeof field.value === "string" ? field.value : ""}
              onChange={field.onChange}
            />
          </FormControl>
          <FormMessage />
        </FormItem>
      )}
    />
  );
}

const ButtonLoadingWrapper = memo(function ButtonLoadingWrapper({
  isLoading,
  loadingText,
  children,
}: {
  isLoading: boolean;
  loadingText: string;
  children: React.ReactNode;
}) {
  if (isLoading) {
    return (
      <>
        <Spinner className="mr-2 h-4 w-4" />
        <span>{loadingText}</span>
      </>
    );
  }

  return <>{children}</>;
});
